-- =========================================================
-- IMPORTAR CORPUS CONVERSACIONAL A dt_ai_memories
-- Este SQL es opcional porque la APP ya carga el corpus desde archivos JSON.
-- Úsalo si quieres que el corpus también quede guardado en Supabase.
-- =========================================================

begin;

on conflict (id) do update
set payload = excluded.payload,
    updated_at = now();

commit;

