insert into public.dt_ai_memories (id, payload, created_at, updated_at)
values
('corpus_kb_0001', '{"id": "corpus_kb_0001", "intent": "saludo", "key": "hola,saludo,ayuda,mesa", "answer": "Hola. Soy el asistente de la Mesa de Ayuda de Calidad. Puedo ayudarte a radicar solicitudes, consultar estados, entender el proceso de calidad y revisar información de tickets según tus permisos.", "category": "Conversaciones normales", "question": "Saludo: Hola", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0002', '{"id": "corpus_kb_0002", "intent": "saludo", "key": "buenos días,ayuda,consulta", "answer": "Buenos días. Cuéntame qué necesitas: radicar una solicitud, consultar un ticket, revisar un estado o entender un paso del proceso de calidad.", "category": "Conversaciones normales", "question": "Buenos días, necesito ayuda", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0003', '{"id": "corpus_kb_0003", "intent": "presentacion_ia", "key": "quién eres,asistente,mesa ayuda", "answer": "Soy el asistente interno de la Mesa de Ayuda de Calidad. Mi función es orientar a los usuarios, consultar información permitida de la app y apoyar el seguimiento del mejoramiento continuo.", "category": "Conversaciones normales", "question": "¿Quién eres?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0004', '{"id": "corpus_kb_0004", "intent": "alcance_ia", "key": "puedes hacer,funciones,capacidad", "answer": "Puedo responder preguntas sobre la mesa de ayuda, orientar radicaciones, explicar estados, consultar tickets permitidos, sugerir acciones y guardar aprendizajes pendientes para revisión del Super Admin.", "category": "Conversaciones normales", "question": "¿Qué puedes hacer?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0005', '{"id": "corpus_kb_0005", "intent": "limite_ia", "key": "decisiones,límites,autorizar", "answer": "No. Puedo orientar y sugerir, pero no debo tomar decisiones críticas, cambiar roles, cerrar tickets o aprobar aprendizajes sin autorización del usuario responsable o del Super Admin.", "category": "Conversaciones normales", "question": "¿Puedes tomar decisiones por mí?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0006', '{"id": "corpus_kb_0006", "intent": "agradecimiento", "key": "gracias,seguimiento", "answer": "Con gusto. Si necesitas, también puedo ayudarte a revisar el siguiente paso del ticket o a redactar una respuesta de seguimiento.", "category": "Conversaciones normales", "question": "Agradecimiento: Gracias", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0007', '{"id": "corpus_kb_0007", "intent": "despedida", "key": "despedida,trazabilidad", "answer": "Perfecto. Dejo la conversación registrada para trazabilidad. Cuando necesites continuar, puedes preguntarme por el ticket, el área o el proceso.", "category": "Conversaciones normales", "question": "Listo, eso era todo", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0008', '{"id": "corpus_kb_0008", "intent": "aclaracion", "key": "no entendí,explicar,simple", "answer": "Te lo explico más simple: dime si quieres crear una solicitud, consultar un ticket, responder un caso, cerrar una actividad o revisar indicadores.", "category": "Conversaciones normales", "question": "No entendí", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0009', '{"id": "corpus_kb_0009", "intent": "orientacion", "key": "perdido,orientación,caso", "answer": "Empecemos por identificar el caso. Dime si tienes número de ticket, área involucrada, responsable o una descripción breve del problema.", "category": "Conversaciones normales", "question": "Estoy perdido, no sé qué hacer", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0010', '{"id": "corpus_kb_0010", "intent": "confianza", "key": "oficial,soporte,datos", "answer": "Uso la base de conocimiento oficial y los datos permitidos de la aplicación. Si no encuentro soporte suficiente, te lo indicaré y no inventaré información.", "category": "Conversaciones normales", "question": "¿Lo que me dices es oficial?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0011', '{"id": "corpus_kb_0011", "intent": "orientacion", "key": "hago,ahora,claro,primero,identifiquemos,describe,ocurre,está,involucrada,existe", "answer": "Claro. Primero identifiquemos el caso: describe qué ocurre, qué área está involucrada, si existe un ticket y qué resultado esperas. Con eso puedo orientarte sin perder trazabilidad.", "category": "Conversaciones normales", "question": "Qué hago ahora", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0012', '{"id": "corpus_kb_0012", "intent": "aclaracion", "key": "explícame,paso,resumo,pasos,identifica,revisa,existe,valida,evidencia,asigna", "answer": "Lo resumo en pasos: identifica el caso, revisa si ya existe ticket, valida evidencia, asigna responsable y registra el seguimiento en la Mesa de Ayuda.", "category": "Conversaciones normales", "question": "Explícame paso a paso", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0013', '{"id": "corpus_kb_0013", "intent": "clasificar_area", "key": "ayudarte,clasificarlo,afecta,cumplimiento,procesos,evidencias,trazabilidad,auditoría,mejora,continua", "answer": "Puedo ayudarte a clasificarlo. Si afecta cumplimiento, procesos, evidencias, trazabilidad, auditoría o mejora continua, probablemente corresponde al proceso de calidad.", "category": "Conversaciones normales", "question": "No sé si esto es de calidad", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0014', '{"id": "corpus_kb_0014", "intent": "escalamiento_humano", "key": "quiero,hablar,alguien,orientarte,pero,requiere,decisión,autorización,debes,escalarlo", "answer": "Puedo orientarte, pero si el caso requiere decisión o autorización, debes escalarlo al responsable del área o al jefe general según el flujo definido.", "category": "Conversaciones normales", "question": "Quiero hablar con alguien", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0015', '{"id": "corpus_kb_0015", "intent": "prioridad", "key": "urgente,marcarlo,existir,impacto,alto,vencimiento,próximo,riesgo,incumplimiento,afectación", "answer": "Para marcarlo como urgente deben existir impacto alto, vencimiento próximo, riesgo de incumplimiento o afectación a varios usuarios. Registra la justificación en el ticket.", "category": "Conversaciones normales", "question": "Esto es urgente", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0016', '{"id": "corpus_kb_0016", "intent": "corregir_solicitud", "key": "equivoqué,está,cerrada,puedes,agregar,comentario,aclaratorio,pedir,ajuste,responsable", "answer": "Si la solicitud aún no está cerrada, puedes agregar un comentario aclaratorio o pedir ajuste al responsable. No se recomienda borrar trazabilidad.", "category": "Conversaciones normales", "question": "Me equivoqué en la solicitud", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0017', '{"id": "corpus_kb_0017", "intent": "confirmar_registro", "key": "quiero,saber,quedó,registrado,confirmarlo,necesito,número,dato,radicado,existe", "answer": "Para confirmarlo necesito el número de ticket o el dato con el que fue radicado. Si existe, te puedo indicar estado, responsable y última actualización permitida.", "category": "Conversaciones normales", "question": "Quiero saber si quedó registrado", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0018', '{"id": "corpus_kb_0018", "intent": "sugerir_accion", "key": "dame,recomendación,documentar,hecho,adjuntar,evidencia,definir,responsable,dejar,acción", "answer": "Mi recomendación es documentar el hecho, adjuntar evidencia, definir responsable y dejar una acción concreta con fecha de seguimiento.", "category": "Conversaciones normales", "question": "Dame una recomendación", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0019', '{"id": "corpus_kb_0019", "intent": "resumir_conversacion", "key": "resume,hablamos,resumir,conversación,tres,partes,situación,reportada,estado,actual", "answer": "Puedo resumir la conversación en tres partes: situación reportada, estado actual y próximo paso sugerido. Si hay ticket asociado, lo usaré como referencia.", "category": "Conversaciones normales", "question": "Resume lo que hablamos", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0020', '{"id": "corpus_kb_0020", "intent": "clasificar_area", "key": "calidad,área,clasificar,responsable", "answer": "Si el caso está relacionado con procedimientos, evidencias, auditoría, acciones de mejora y seguimiento del sistema de gestión, puede clasificarse para el área de Calidad. Si el impacto cruza varias áreas, conviene radicarlo con área principal y mencionar las áreas relacionadas.", "category": "Conversaciones del área", "question": "¿Esto lo debe revisar Calidad?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0021', '{"id": "corpus_kb_0021", "intent": "consultar_responsable_area", "key": "calidad,responsable,asignado,usuarios", "answer": "La respuesta depende de los usuarios configurados en la aplicación. Puedo consultar el responsable si existe en la base de datos. Si no hay responsable asignado, el caso debe escalarse al jefe general o al Super Admin para configuración.", "category": "Conversaciones del área", "question": "¿Quién responde los casos de Calidad?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0022', '{"id": "corpus_kb_0022", "intent": "crear_ticket_area", "key": "calidad,radicar,solicitud,prioridad", "answer": "Para radicarla en Calidad, registra una descripción clara, selecciona el área correspondiente, define prioridad, adjunta evidencia si aplica y confirma el solicitante. Si el caso afecta calidad, incluye el impacto o riesgo observado.", "category": "Conversaciones del área", "question": "Necesito radicar una solicitud para Calidad", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0023', '{"id": "corpus_kb_0023", "intent": "resumen_area", "key": "calidad,resumen,pendiente,tickets", "answer": "Puedo generar el resumen consultando los tickets abiertos, vencidos, en espera y cerrados del área de Calidad. Para hacerlo correctamente necesito acceso a los datos o filtros de fecha definidos.", "category": "Conversaciones del área", "question": "Dame un resumen de lo pendiente de Calidad", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0024', '{"id": "corpus_kb_0024", "intent": "clasificar_area", "key": "talento humano,área,clasificar,responsable", "answer": "Si el caso está relacionado con inducción, capacitación, novedades de personal, soportes y solicitudes administrativas, puede clasificarse para el área de Talento Humano. Si el impacto cruza varias áreas, conviene radicarlo con área principal y mencionar las áreas relacionadas.", "category": "Conversaciones del área", "question": "¿Esto lo debe revisar Talento Humano?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
