('corpus_kb_0095', '{"id": "corpus_kb_0095", "intent": "agregar_comentario", "key": "quiero,agregar,comentario,puedes,agregarlo,seguimiento,claro,relacionado,conservar,trazabilidad", "answer": "Puedes agregarlo como seguimiento del ticket. El comentario debe ser claro, relacionado con el caso y conservar trazabilidad. No reemplaza la evidencia cuando esta es obligatoria.", "category": "Seguimiento y cierre", "question": "Quiero agregar un comentario", "source": "Corpus conversacional IA mesa de ayuda", "weight": 8, "active": true}'::jsonb, now(), now()),
