('corpus_kb_0124', '{"id": "corpus_kb_0124", "intent": "aprendizaje_pendiente", "key": "aprende,evidencia,cerrarse,registrado,aprendizaje,pendiente,aprobación,usaré,regla,oficial", "answer": "He registrado ese aprendizaje como pendiente de aprobación. No lo usaré como regla oficial hasta que el Super Admin lo revise y lo apruebe.", "category": "Aprendizaje controlado", "question": "Aprende que los tickets sin evidencia no deben cerrarse", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0125', '{"id": "corpus_kb_0125", "intent": "aprendizaje_pendiente", "key": "recuerda,revisa,auditoría,guardarlo,aprendizaje,pendiente,convertirlo,conocimiento,oficial,revisarse", "answer": "Puedo guardarlo como aprendizaje pendiente. Para convertirlo en conocimiento oficial debe revisarse y aprobarse en el panel de aprendizaje.", "category": "Aprendizaje controlado", "question": "Recuerda que Calidad revisa las solicitudes de auditoría", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0126', '{"id": "corpus_kb_0126", "intent": "feedback_respuesta", "key": "corrige,respuesta,gracias,corrección,registraré,comentario,revisión,regla,oficial,diferente", "answer": "Gracias por la corrección. Registraré el comentario para revisión. Si hay una regla oficial diferente, el Super Admin puede actualizar la base de conocimiento.", "category": "Aprendizaje controlado", "question": "Esto no era así, corrige esa respuesta", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0127', '{"id": "corpus_kb_0127", "intent": "feedback_respuesta", "key": "respondas,entendido,registraré,observación,mejorar,respuesta,deseas,proponer,versión,corregida", "answer": "Entendido. Registraré la observación para mejorar la respuesta. Si deseas, puedo proponer una versión corregida para aprobación.", "category": "Aprendizaje controlado", "question": "No respondas eso así", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0128', '{"id": "corpus_kb_0128", "intent": "conocimiento_obsoleto", "key": "información,aplica,marcaré,observación,posible,conocimiento,obsoleto,revisarse,antes,desactivar", "answer": "Marcaré la observación como posible conocimiento obsoleto. Debe revisarse antes de desactivar o reemplazar la respuesta oficial.", "category": "Aprendizaje controlado", "question": "Esa información ya no aplica", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0129', '{"id": "corpus_kb_0129", "intent": "aprendizaje_pendiente", "key": "guarda,instrucción,guardaré,aprendizaje,pendiente,quedará,activa,hasta,validada,administrador", "answer": "La guardaré como aprendizaje pendiente. No quedará activa hasta que sea validada por el administrador correspondiente.", "category": "Aprendizaje controlado", "question": "Guarda esta instrucción", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0130', '{"id": "corpus_kb_0130", "intent": "resumir_aprendizaje", "key": "aprendiste,conversación,detecté,posibles,aprendizajes,criterios,atención,evidencia,seguimiento,enviarlos", "answer": "Detecté posibles aprendizajes sobre criterios de atención, evidencia y seguimiento. Puedo enviarlos a revisión para que se aprueben o descarten.", "category": "Aprendizaje controlado", "question": "¿Qué aprendiste de esta conversación?", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0131', '{"id": "corpus_kb_0131", "intent": "manejo_inconformidad", "key": "molesto,nadie,responde,entiendo,molestia,revisemos,última,actualización,responsable,asignado", "answer": "Entiendo la molestia. Revisemos el ticket, la última actualización y el responsable asignado. Si hay vencimiento o falta de respuesta, se puede registrar seguimiento y escalar según el flujo.", "category": "Conversaciones difíciles", "question": "Estoy molesto porque nadie responde", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0132', '{"id": "corpus_kb_0132", "intent": "manejo_inconformidad", "key": "sirve,nada,lamento,respuesta,haya,sido,útil,corregirlo,necesito,identificar", "answer": "Lamento que la respuesta no haya sido útil. Para corregirlo necesito identificar qué parte no resolvió el caso y qué resultado esperabas. Lo dejaremos documentado.", "category": "Conversaciones difíciles", "question": "Eso no sirve para nada", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0133', '{"id": "corpus_kb_0133", "intent": "escalamiento_humano", "key": "quiero,hablar,jefe,orientar,escalamiento,hacerlo,correctamente,registrar,razón,asociado", "answer": "Puedo orientar el escalamiento. Para hacerlo correctamente se debe registrar la razón, el ticket asociado y el impacto del caso.", "category": "Conversaciones difíciles", "question": "Quiero hablar con el jefe ya", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
('corpus_kb_0134', '{"id": "corpus_kb_0134", "intent": "queja_responsable", "key": "responsable,nunca,contesta,registra,observación,revisa,fecha,último,movimiento,supera", "answer": "Registra la observación en el ticket y revisa la fecha del último movimiento. Si supera el tiempo acordado, puede escalarse con trazabilidad.", "category": "Conversaciones difíciles", "question": "El responsable nunca contesta", "source": "Corpus conversacional IA mesa de ayuda", "weight": 6, "active": true}'::jsonb, now(), now()),
